interface.definition:
a!localVariables(
  local!loggedInUser: loggedInUser(),
  local!onlyGeneralEnforcementService: not(#"urn:appian:function:v1:a:isusermemberofgroup?okey=a!isUserMemberOfGroup"(
    username: local!loggedInUser,
    groups: {ri!prison[#"urn:appian:record-field:v1:c035ef79-0201-4600-a2b7-9075b42e1d87/e260c1e3-8ec5-4746-99a2-f9dcba23540a"], ri!prison[#"urn:appian:record-field:v1:c035ef79-0201-4600-a2b7-9075b42e1d87/de30f4cc-6494-41c4-afb6-d73c42bdadbf"]}
  )),
  local!existingOpinions: #"SYSTEM_SYSRULES_forEach"(
    items: property(#"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1488848"(
      eventId: ri!eventID,
      assignee: if(local!onlyGeneralEnforcementService,loggedInUser(),null)
    ),"data",null),
    expression: a!map(
      index: fv!index,
      opinion: fv!item
    )
  ),
  local!selectedOpinion: if(
    a!isNullOrEmpty(local!existingOpinions),
    null,
    1
  ),
  {
    if(
      a!isNullOrEmpty(local!existingOpinions),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        label: "Empty Message",
        value: #"SYSTEM_SYSRULES_richTextItem_v1"(
          text: #"urn:appian:translation-string:v1:3dbae095-aa05-4bf0-984b-31e272ce8782",
          style: "STRONG"
        )
      ),
      {
        #"SYSTEM_SYSRULES_cardChoiceField"(
          data: local!existingOpinions,
          value: local!selectedOpinion,
          saveInto: local!selectedOpinion,
          maxSelections: 1,
          cardTemplate: #"SYSTEM_SYSRULES_cardTemplateBarTextJustified"(
            id: fv!index,
            primaryText: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1546843"(user: property(fv!data,"opinion",null)[#"urn:appian:record-field:v1:d20e13d7-6450-4ab5-8eb8-31b00904e791/80d59003-45f5-4439-ba3b-56108d2077a6"]),
            secondaryText: concat(property(fv!data,"opinion",null)[#"urn:appian:record-field:v1:d20e13d7-6450-4ab5-8eb8-31b00904e791/b816fde2-3f17-4fae-984d-c99216d6a968"], char(10), #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: property(fv!data,"opinion",null)[#"urn:appian:record-field:v1:d20e13d7-6450-4ab5-8eb8-31b00904e791/7a40d312-440e-4abc-b6ed-1c02db722889"]))
          )
        ),
        #"SYSTEM_SYSRULES_richTextDisplayField"(
          showWhen: a!isNotNullOrEmpty(local!selectedOpinion),
          label: #"urn:appian:translation-string:v1:7751d15b-99f7-4029-9f5d-fcd2123beea5",
          value: #"SYSTEM_SYSRULES_richTextItem_v1"(
            text: property(local!existingOpinions,"opinion",null)[#"urn:appian:record-field:v1:d20e13d7-6450-4ab5-8eb8-31b00904e791/46aa4cc9-8ea1-46cd-a540-003d2657448f"][local!selectedOpinion],
          )
        ),
        #"SYSTEM_SYSRULES_styledTextEditorField"(
          showWhen: a!isNotNullOrEmpty(local!selectedOpinion),
          label: #"urn:appian:translation-string:v1:441c1091-3855-43b0-b14b-488a2296a020",
          sizeLimit: #"_a-0000ee09-79c9-8000-9bf0-011c48011c48_1477556",
          readOnly: true,
          value: property(local!existingOpinions,"opinion",null)[#"urn:appian:record-field:v1:d20e13d7-6450-4ab5-8eb8-31b00904e791/da2c05ff-925e-4e4e-91e1-775827dd348a"][local!selectedOpinion]
        )
      }
    )
  }
)
